INSERT INTO "faqs" ("id","category","topic_id","topic_title","topic_icon","topic_description","subtopic_id","subtopic_title","question","answer","order","created_at","updated_at") VALUES (1,'home',NULL,NULL,NULL,NULL,NULL,NULL,'What is Cureza?','Cureza is India''s leading online marketplace for authentic Ayurvedic and wellness products. We connect verified sellers with customers looking for natural health solutions.',1,'2026-06-17 19:26:37','2026-06-17 19:26:37'),
 (2,'home',NULL,NULL,NULL,NULL,NULL,NULL,'Is free shipping available?','Yes! We offer free shipping on all orders above ₹499. For orders below this amount, a nominal shipping fee of ₹49 applies.',2,'2026-06-17 19:26:37','2026-06-17 19:26:37'),
 (3,'home',NULL,NULL,NULL,NULL,NULL,NULL,'Are all products authentic?','Absolutely. All products on Cureza are sourced from verified manufacturers and sellers. We ensure 100% authenticity and quality checks before listing.',3,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (4,'home',NULL,NULL,NULL,NULL,NULL,NULL,'Can I consult with a doctor?','Yes, we have certified Ayurvedic doctors available for online consultations. Book a video consultation starting at just ₹299.',4,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (5,'home',NULL,NULL,NULL,NULL,NULL,NULL,'What is your return policy?','We offer a 7-day easy return policy for most products. If you''re not satisfied with your purchase, you can return it within 7 days for a full refund.',5,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (6,'home',NULL,NULL,NULL,NULL,NULL,NULL,'How can I track my order?','Once your order is shipped, you''ll receive a tracking link via email and SMS. You can also track your order from your account dashboard.',6,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (7,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','How do I track my order?','You can track your order via the "My Orders" section. Updates are also sent on SMS and email.',1,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (8,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','Why is my order stuck on processing?','Since Cureza is a multi-vendor marketplace, some vendors require extra time for stock confirmation.',2,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (9,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','My tracking link is not updating. What should I do?','Tracking may take 12–24 hours to update. If still not updated, contact support at help@cureza.in.',3,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (10,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','Can I change my address after placing the order?','Address changes are only possible before the order is shipped. Contact support immediately.',4,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (11,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','My order shows delivered but I did not receive it.','Please check with security or neighbors. If still missing, contact us for investigation.',5,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (12,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','Will I get WhatsApp updates for my order?','Yes, if WhatsApp notifications are enabled in your Cureza account settings.',6,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (13,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','Why is my order split into multiple shipments?','Items from different vendors ship separately. Each vendor handles their own logistics.',7,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (14,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','Can I check my delivery partner details?','Yes, courier details are visible in the tracking section once dispatched.',8,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (15,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','Can someone else receive my package?','Yes, delivery is allowed to family/neighbors if they confirm your name and OTP.',9,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (16,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','tracking','Track Order','What happens if delivery fails?','Courier will attempt delivery again. If still unsuccessful, contact Cureza support.',10,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (17,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','How can I cancel my order?','Go to "My Orders" and request cancellation before the vendor ships your item.',11,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (18,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','Can I cancel a shipped order?','No, shipped orders cannot be cancelled. You may refuse delivery if needed.',12,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (19,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','Will I get a refund for cancelled orders?','Yes, refunds for prepaid orders are processed within 5–7 working days.',13,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (20,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','Can a vendor cancel my order?','Yes, if the vendor faces stock issues or quality concerns. You will be refunded.',14,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (21,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','Can I cancel one item from a multi-item order?','Yes, cancellation is available per item if not yet shipped.',15,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (22,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','How do I know if my cancellation was successful?','You will receive an SMS/email confirmation from Cureza.',16,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (23,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','Can I cancel a COD order?','Yes, COD orders can be cancelled before dispatch.',17,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (24,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','What if I accidentally cancelled my order?','You will need to place a new order. Cancelled orders cannot be revived.',18,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (25,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','Why was my cancellation request rejected?','It may be because the vendor has already shipped the product.',19,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (26,'help','orders','Orders','ShoppingBag','Track, cancel, or manage your orders on Cureza.','cancellation','Order Cancellation','Who should I contact for cancellation support?','Email us anytime at help@cureza.in — we offer 24/7 support.',20,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (27,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','What are the shipping charges?','Shipping is free for orders above ₹499. Below that, a flat ₹40 charge applies.',21,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (28,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Do vendors charge additional fees?','No, Cureza standardizes shipping fees for all vendors.',22,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (29,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Do you ship internationally?','Currently, we only deliver within India.',23,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (30,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Is COD included in shipping?','COD has an additional small convenience fee depending on seller policies.',24,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (31,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Why do some items have free shipping?','Some vendors offer free shipping promotions.',25,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (32,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Will I see shipping charges before placing an order?','Yes, shipping charges appear on the checkout page.',26,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (33,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Are shipping charges refundable?','Shipping charges are refundable only for cancelled prepaid orders before dispatch.',27,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (34,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Does Cureza offer express delivery?','Express delivery is available on selected products and vendors.',28,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (35,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Why do shipping charges vary?','Charges depend on location, weight, and vendor logistics.',29,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (36,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','charges','Shipping Charges','Can I get free shipping for multiple items?','Yes, if the combined cart amount exceeds ₹499.',30,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (37,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','When will I get my order?','Most orders arrive within 3–5 working days. Remote areas may take 7–9 days.',31,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (38,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','Why is delivery taking longer?','Vendor location, courier delays, holidays, or high-demand periods may affect delivery.',32,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (39,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','Can I schedule my delivery?','Scheduled delivery is not available yet but coming soon.',33,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (40,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','Which courier partners does Cureza use?','We ship with leading partners like Delhivery, BlueDart, Xpressbees, and Ekart.',34,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (41,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','How do I change the delivery date?','Contact the courier using the tracking link. Options depend on courier availability.',35,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (42,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','Do you deliver to rural areas?','Yes, Cureza delivers to 28,000+ pin codes across India.',36,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (43,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','Can I request contactless delivery?','Yes, mention it in delivery instructions or inform the courier.',37,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (44,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','What if I miss the delivery?','Couriers make up to 3 attempts before returning the order.',38,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (45,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','Can I check delivery time slots?','Time slots are visible on the tracking page if enabled by the courier.',39,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (46,'help','shipping','Shipping & Delivery','Truck','Understand shipping charges, timelines, and courier partners.','delivery','Delivery Timelines','Do you deliver on weekends?','Yes, most courier partners deliver on Saturdays and sometimes Sundays.',40,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (47,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','What is Cureza’s return policy?','Returns are accepted within 7 days for damaged, defective, or incorrect products.',41,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (48,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','Are all products returnable?','Personal care, health, hygiene and consumable items are non-returnable.',42,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (49,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','Can I return an item from a multi-vendor order?','Yes, returns are processed per-item depending on vendor policies.',43,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (50,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','How do I request a return?','Go to "My Orders" > Select Item > Request Return.',44,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (51,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','Do I need to keep the original packaging?','Yes, original packaging and unused condition is required for approval.',45,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (52,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','Who handles return pickups?','Cureza arranges pickup through courier partners.',46,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (53,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','Why was my return request rejected?','If the item shows signs of use, damage, or missing accessories.',47,'2026-06-17 19:26:38','2026-06-17 19:26:38'),
 (54,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','Can I exchange the product instead?','Exchanges are vendor-specific and available on selected items.',48,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (55,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','What happens if courier cannot pick up my return?','We will reschedule the pickup at your convenience.',49,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (56,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','policy','Return Policy','How can I contact support for returns?','Email help@cureza.in for 24/7 return assistance.',50,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (57,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','When will I receive my refund?','Refunds are processed within 48 hours of pickup and take 3–7 days to reflect.',51,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (58,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','Where will my refund be credited?','Refunds go back to the original payment method.',52,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (59,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','How do I track my refund?','You can check refund status in the "My Orders" or "Refunds" section.',53,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (60,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','I paid by COD. How will I get my refund?','Refunds for COD orders are sent via bank transfer or UPI.',54,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (61,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','My refund is delayed. What should I do?','Contact support with your order ID — help@cureza.in.',55,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (62,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','Will shipping charges be refunded?','Shipping charges are refunded only for cancelled prepaid orders before shipping.',56,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (63,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','Why is my refund partial?','If only certain items were returned or if they did not meet return conditions.',57,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (64,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','Can I change my refund mode?','Refund mode cannot be changed once initiated.',58,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (65,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','When do replacement refunds happen?','Replacement refunds are processed after quality check by the vendor.',59,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (66,'help','returns','Returns & Refunds','RefreshCw','Learn about returns, refunds, and replacement policies.','refund-status','Refund Status','Do vendors issue refunds?','Refunds are processed by Cureza to ensure fast and secure payouts.',60,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (67,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','How do I update my profile details?','Go to My Account → Edit Profile → Save Changes.',61,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (68,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','How can I reset my password?','Use the "Forgot Password" option on the login page.',62,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (69,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','Can I change my mobile number?','Yes, you can update it in your account settings after OTP verification.',63,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (70,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','Is my personal data safe with Cureza?','Yes, Cureza uses industry-level encryption and privacy protection.',64,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (71,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','How do I delete my Cureza account?','Contact support at help@cureza.in to request account deletion.',65,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (72,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','How can I manage my addresses?','Under "Address Book", you can add, edit, or delete addresses.',66,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (73,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','Where can I see my saved payment methods?','Saved payment methods are available under "Payments & Wallet".',67,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (74,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','Can I enable 2-step verification?','Yes, 2-step login protection is available for extra security.',68,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (75,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','How do I view my past orders?','Simply visit "My Orders" in your account dashboard.',69,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (76,'help','account','My Account','User','Manage your Cureza profile, security, and preferences.','profile','Profile Settings','Can I recover my account if I forget my email?','Contact Cureza support with identity proof.',70,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (77,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','What payment methods do you accept?','We accept UPI, Cards, Net Banking, Wallets, and Cash on Delivery.',71,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (78,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','Is Cash on Delivery available everywhere?','COD availability depends on your pin code and vendor settings.',72,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (79,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','My payment failed but money was deducted.','Refunds for failed payments are auto-processed within 2–4 business days.',73,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (80,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','Can I pay via Paytm or PhonePe?','Yes, all major UPI apps are supported.',74,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (81,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','Does Cureza offer EMI options?','EMI is available on selected bank cards during checkout.',75,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (82,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','Is there a Cureza Wallet?','Yes, refunds for COD orders are faster with Cureza Wallet.',76,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (83,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','Can I save my card info?','Yes, securely stored via RBI-approved tokenization.',77,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (84,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','Why is COD not available on some items?','High-value or fragile items may have COD disabled.',78,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (85,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','Do you charge extra for COD?','Some vendors may apply a small COD convenience fee.',79,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (86,'help','payments','Payments','CreditCard','Payment options, failed transactions, and COD help.','modes','Payment Modes','Can I split payment using multiple methods?','Currently not supported.',80,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (87,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','How do I apply a coupon code?','Apply the code at checkout before completing the payment.',81,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (88,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Why is my coupon not working?','It may be expired, product-restricted, or vendor-specific.',82,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (89,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Can I use multiple coupons?','Only one coupon can be applied per order.',83,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (90,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Do vendors offer separate coupons?','Yes, some vendors run exclusive promotions.',84,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (91,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Find offers','Check the "Offers" section on the homepage.',85,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (92,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Are coupons available on COD orders?','Yes, most coupons work on COD as well.',86,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (93,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Can I apply a coupon after placing the order?','No, coupons must be applied before payment.',87,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (94,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Do coupons work during sales?','Some coupons may be disabled during mega events.',88,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (95,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Do vendor discounts apply automatically?','Yes, vendor-specific offers appear automatically at checkout.',89,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (96,'help','offers','Offers & Coupons','Gift','Apply coupons, earn rewards, and get vendor discounts.','coupons','Coupons & Discounts','Can I transfer unused coupons to another account?','No, coupons are non-transferable.',90,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (97,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','Are products on Cureza authentic?','Yes, all vendors are verified and products are sourced from authorized suppliers.',91,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (98,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','How does Cureza verify vendors?','We check GST, business licenses, product quality, and past performance.',92,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (99,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','Are payments secure?','Yes, we use encrypted payment gateways with RBI-compliant security.',93,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (100,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','Can I trust reviews on Cureza?','Reviews are from real customers who purchased the product.',94,'2026-06-17 19:26:39','2026-06-17 19:26:39'),
 (101,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','Is my data safe?','We follow strict data protection standards and do not share personal data.',95,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (102,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','How do I report a fake product?','Send details to help@cureza.in and our team will take strict action.',96,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (103,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','Do vendors undergo quality checks?','Yes, Cureza monitors vendor performance regularly.',97,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (104,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','Is Cureza a registered company?','Yes, headquartered in Jaipur, Rajasthan, India.',98,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (105,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','How do I identify trusted sellers?','Look for “Verified Vendor” badge on product listings.',99,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (106,'help','safety','Safety & Trust','ShieldCheck','Your safety is our priority. 100% genuine products.','authenticity','Authenticity & Trust','Does Cureza provide buyer protection?','Yes, Cureza ensures full protection for defective or incorrect items.',100,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (107,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','How do I book a consultation?','Go to “Consult Doctor”, select a doctor, choose a time slot, and confirm the booking.',101,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (108,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','Are doctors verified?','Yes, all doctors on Cureza are certified and verified by our medical team.',102,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (109,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','Can I reschedule my consultation?','Yes, rescheduling is allowed up to 2 hours before the session.',103,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (110,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','Do doctors give prescriptions?','Yes, digital prescriptions are provided after your session.',104,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (111,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','Are consultations private?','All online sessions are encrypted and confidential.',105,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (112,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','How long does a consultation take?','Most sessions last 10–20 minutes depending on the doctor.',106,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (113,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','Is video calling necessary?','No, you can choose audio, video, or chat-based consultations.',107,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (114,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','Can I book for a family member?','Yes, simply mention patient details while booking.',108,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (115,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','What if the doctor misses the call?','Your session will be rescheduled or refunded.',109,'2026-06-17 19:26:40','2026-06-17 19:26:40'),
 (116,'help','consultation','Doctor Consultation','MessageCircle','Book online consultations with certified doctors.','booking','Consultation Booking','How do I contact support for consultation issues?','Email us 24/7 at help@cureza.in.',110,'2026-06-17 19:26:40','2026-06-17 19:26:40');
