INSERT INTO "store_change_requests" ("id","seller_id","brand_id","proposed_data","status","rejection_reason","reviewed_by","reviewed_at","created_at","updated_at") VALUES (2,5,2,'{"name":"Aura Wellness","short_description":"Feel The Shift","description":"Aglowsciences Marketing Llp\r\nWe provide some of the finest cbd oils in india, crafted from natural, plant-based ingredients to support your overall well-being. Our formulations are thoughtfully designed to help manage everyday concerns like pain relief, improved immunity, better sleep, and enhanced hair and skin health.\r\n\r\nMade with high-quality extracts and carefully tested for purity and consistency, our products aim to deliver effective, gentle support without disrupting your daily routine. We also extend our range to pet care, offering safe and reliable solutions for your furry companions.","keywords":[],"logo":"\/storage\/brands\/logos\/sVMuiVRzMNToQOROvNAPwxSV0L076pm2LKILs0IZ.png","banner_path":"\/storage\/brands\/banners\/KRO2jiPwGsHfr5CnAXIhS3uw7YgvueoKx6TbZxVa.png","meta_title":"We provide some of the finest cbd oils in india, crafted from natural, plant-based ingredients to support your overall well-being","meta_description":"Our formulations are thoughtfully designed to help manage everyday concerns like pain relief, improved immunity, better sleep, and enhanced hair and skin health.\r\n\r\nMade with high-quality extracts and carefully tested for purity and consistency, our products aim to deliver effective, gentle support without disrupting your daily routine. We also extend our range to pet care, offering safe and reliable solutions for your furry companions.","meta_keywords":"Wellness","faqs":[{"question":"Are all products authentic?","answer":"Absolutely. All products on Cureza are sourced from verified manufacturers and sellers. We ensure 100% authenticity and quality checks before listing."},{"question":"Is free shipping available?","answer":"Yes! We offer free shipping on all orders above \u2