BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "activity_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "action" varchar not null, "description" text, "ip_address" varchar, "user_agent" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "addresses" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "phone" varchar not null, "address_line_1" varchar not null, "address_line_2" varchar, "city" varchar not null, "state" varchar not null, "zip" varchar not null, "country" varchar not null default 'India', "type" varchar not null default 'home', "is_default" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "admin_roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "permissions" text not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "appointments" ("id" integer primary key autoincrement not null, "doctor_id" integer not null, "patient_id" integer not null, "appointment_date" datetime not null, "status" varchar check ("status" in ('pending', 'confirmed', 'completed', 'cancelled')) not null default 'pending', "notes" text, "created_at" datetime, "updated_at" datetime, "consultation_type" varchar, "is_follow_up" tinyint(1) not null default '0', "urgency_level" varchar not null default 'normal', "health_concern" text, "medical_background" text, "documents" text, "preferred_slot" varchar, "reschedule_allowed" tinyint(1) not null default '1', "consent_accepted" tinyint(1) not null default '0', "payment_status" varchar not null default 'pending', "payment_method" varchar, "amount" numeric, "payment_id" varchar, "payment_details" text, foreign key("doctor_id") references "users"("id") on delete cascade, foreign key("patient_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "attribute_terms" ("id" integer primary key autoincrement not null, "attribute_id" integer not null, "name" varchar not null, "slug" varchar not null, "value" varchar, "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("attribute_id") references "attributes"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "attribute_values" ("id" integer primary key autoincrement not null, "attribute_id" integer not null, "value" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("attribute_id") references "attributes"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "attributes" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "type" varchar not null default 'select', "is_active" tinyint(1) not null default '1', "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "badges" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" text not null, "icon" varchar not null, "rule_type" varchar not null, "rule_value" integer not null, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "banners" ("id" integer primary key autoincrement not null, "title" varchar not null, "image" varchar not null, "location" varchar not null, "status" varchar not null default 'Active', "link" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "blog_authors" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "bio" text, "image" varchar, "social_links" text, "created_at" datetime, "updated_at" datetime, "meta_title" varchar, "meta_description" text, "meta_keywords" varchar);
CREATE TABLE IF NOT EXISTS "blog_categories" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "icon" varchar, "is_active" tinyint(1) not null default '1', "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, "meta_title" varchar, "meta_description" text, "meta_keywords" varchar);
CREATE TABLE IF NOT EXISTS "blog_post_tags" ("id" integer primary key autoincrement not null, "blog_post_id" integer not null, "tag_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("blog_post_id") references "blog_posts"("id") on delete cascade, foreign key("tag_id") references "blog_tags"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "blog_posts" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "excerpt" text, "content" text not null, "featured_image" varchar, "category_id" integer not null, "author_id" integer not null, "status" varchar check ("status" in ('draft', 'published', 'archived')) not null default 'draft', "published_at" datetime, "is_featured" tinyint(1) not null default '0', "meta_title" varchar, "meta_description" varchar, "meta_keywords" varchar, "views_count" integer not null default '0', "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, "fact_checked_by" varchar, "fact_checker_title" varchar, "fact_checker_image" varchar, "fact_checker_credentials" text, "recommended_products" text, "citations" text, foreign key("category_id") references "blog_categories"("id") on delete cascade, foreign key("author_id") references "blog_authors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "blog_tags" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "created_at" datetime, "updated_at" datetime, "meta_title" varchar, "meta_description" text, "meta_keywords" varchar);
CREATE TABLE IF NOT EXISTS "brand_category" ("id" integer primary key autoincrement not null, "brand_id" integer not null, "category_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("brand_id") references "brands"("id") on delete cascade, foreign key("category_id") references "categories"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "brands" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "logo" varchar, "description" text, "user_id" integer not null, "created_at" datetime, "updated_at" datetime, "is_active" tinyint(1) not null default ('1'), "banner_path" varchar, "short_description" text, "keywords" text, "meta_title" varchar, "meta_description" text, "meta_keywords" varchar, "faqs" text, "purity_standards" text, "genuine_badge_text" varchar, "brand_vision" text, "show_in_mega_menu" tinyint(1) not null default '1', "mega_menu_section" varchar, foreign key("user_id") references users("id") on delete set null on update no action);
CREATE TABLE IF NOT EXISTS "bundle_offers" ("id" integer primary key autoincrement not null, "main_product_id" integer not null, "bundled_product_ids" text not null, "discount_percentage" integer not null, "title" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("main_product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "campaigns" ("id" integer primary key autoincrement not null, "title" varchar not null, "subject" varchar not null, "segment" varchar not null, "template" varchar not null, "status" varchar not null default 'queued', "recipients" integer not null default '0', "delivered" integer not null default '0', "open_rate" integer not null default '0', "sent_at" datetime, "created_at" datetime, "updated_at" datetime, "body" text, "scheduled_at" datetime, "total_sent" integer not null default '0', "total_opened" integer not null default '0', "total_clicked" integer not null default '0', "total_failed" integer not null default '0', "channel" varchar not null default 'email', "settings" text);
CREATE TABLE IF NOT EXISTS "cart_items" ("id" integer primary key autoincrement not null, "cart_id" integer not null, "product_id" integer not null, "quantity" integer not null default ('1'), "price" numeric not null, "patient_name" varchar, "patient_age" integer, "patient_gender" varchar, "health_concern" text, "prescription_path" varchar, "created_at" datetime, "updated_at" datetime, "doctor_id" integer, "is_gift" tinyint(1) not null default '0', foreign key("product_id") references products("id") on delete cascade on update no action, foreign key("cart_id") references carts("id") on delete cascade on update no action, foreign key("doctor_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "carts" ("id" integer primary key autoincrement not null, "user_id" integer, "session_id" varchar, "created_at" datetime, "updated_at" datetime, "coupon_code" varchar, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "categories" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "type" varchar check ("type" in ('category', 'concern')) not null, "parent_id" integer, "image" varchar, "icon" varchar, "sub_heading" varchar, "description" text, "bottom_description" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "show_in_mega_menu" tinyint(1) not null default '1', "mega_menu_section" varchar, foreign key("parent_id") references "categories"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "challenges" ("id" integer primary key autoincrement not null, "title" varchar not null, "description" text not null, "type" varchar not null, "goal_value" integer not null, "reward_points" integer not null, "start_date" datetime not null, "end_date" datetime not null, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "collection_product" ("collection_id" integer not null, "product_id" integer not null, foreign key("collection_id") references "collections"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade, primary key ("collection_id", "product_id"));
CREATE TABLE IF NOT EXISTS "collections" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "image" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "communication_logs" ("id" integer primary key autoincrement not null, "recipient" varchar not null, "subject" varchar not null, "provider_name" varchar, "template_key" varchar, "status" varchar not null default 'queued', "retry_count" integer not null default '0', "response" text, "smtp_used" varchar, "error_details" text, "variables" text, "sent_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "communication_smtp_settings" ("id" integer primary key autoincrement not null, "provider_name" varchar not null, "host" varchar not null, "port" integer not null, "username" varchar not null, "password" text not null, "encryption" varchar not null default 'tls', "sender_name" varchar not null, "sender_email" varchar not null, "reply_to" varchar, "timeout" integer not null default '30', "retry_count" integer not null default '3', "max_emails_per_hour" integer not null default '100', "max_emails_per_day" integer not null default '1000', "is_active" tinyint(1) not null default '0', "is_backup" tinyint(1) not null default '0', "priority" integer not null default '1', "notes" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "communication_subscribers" ("id" integer primary key autoincrement not null, "email" varchar not null, "name" varchar, "status" varchar not null default 'pending', "double_opt_in_token" varchar, "double_opt_in_verified_at" datetime, "tags" text, "segments" text, "created_at" datetime, "updated_at" datetime, "phone" varchar);
CREATE TABLE IF NOT EXISTS "communication_templates" ("id" integer primary key autoincrement not null, "key" varchar not null, "name" varchar not null, "subject" varchar not null, "body" text not null, "variables" text, "is_active" tinyint(1) not null default '1', "theme" varchar not null default 'light', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "comparisons" ("id" integer primary key autoincrement not null, "user_id" integer not null, "product_ids" text not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "coupons" ("id" integer primary key autoincrement not null, "code" varchar not null, "type" varchar check ("type" in ('fixed', 'percent')) not null, "value" numeric not null, "min_cart_value" numeric, "expires_at" datetime, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "faqs" ("id" integer primary key autoincrement not null, "category" varchar not null default 'help', "topic_id" varchar, "topic_title" varchar, "topic_icon" varchar, "topic_description" text, "subtopic_id" varchar, "subtopic_title" varchar, "question" text not null, "answer" text not null, "order" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "hsn_codes" ("id" integer primary key autoincrement not null, "code" varchar not null, "description" text not null, "gst_rate" numeric not null default '18', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "influencer_messages" ("id" integer primary key autoincrement not null, "customer_id" integer not null, "subject" varchar not null, "message" text not null, "status" varchar not null default 'pending', "reply_text" text, "replied_by" integer, "replied_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("customer_id") references "users"("id") on delete cascade, foreign key("replied_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "legal_pages" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "description" text, "content" text not null, "status" varchar not null default 'Published', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "media" ("id" integer primary key autoincrement not null, "file_id" varchar, "url" text not null, "thumbnail_url" text, "file_name" varchar not null, "folder_id" integer, "width" integer, "height" integer, "size_bytes" integer not null, "extension" varchar not null, "title" varchar, "alt_text" varchar, "caption" text, "description" text, "tags" text, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("folder_id") references "media_folders"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "media_folders" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "parent_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("parent_id") references "media_folders"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "membership_tiers" ("id" integer primary key autoincrement not null, "name" varchar not null, "min_points" integer not null, "benefits" text, "icon" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "menu_items" ("id" integer primary key autoincrement not null, "title" varchar not null, "url" varchar, "parent_id" integer, "order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("parent_id") references "menu_items"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "notification_logs" ("id" integer primary key autoincrement not null, "recipient_email" varchar, "recipient_phone" varchar, "recipient_name" varchar, "template_code" varchar not null, "flow" varchar not null, "channel" varchar not null, "subject" varchar, "content" text not null, "status" varchar not null, "error_message" text, "sent_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "notification_templates" ("id" integer primary key autoincrement not null, "name" varchar not null, "code" varchar not null, "flow" varchar not null, "channel" varchar not null, "subject" varchar, "content" text not null, "trigger_type" varchar not null default 'event', "delay_value" integer not null default '0', "delay_unit" varchar not null default 'hours', "status" varchar not null default 'active', "whatsapp_template_name" varchar, "whatsapp_status" varchar not null default 'approved', "variables" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "notifications" ("id" varchar not null, "type" varchar not null, "notifiable_type" varchar not null, "notifiable_id" integer not null, "data" text not null, "read_at" datetime, "created_at" datetime, "updated_at" datetime, primary key ("id"));
CREATE TABLE IF NOT EXISTS "order_items" ("id" integer primary key autoincrement not null, "order_id" integer not null, "product_id" integer not null, "seller_id" integer, "product_name" varchar not null, "quantity" integer not null, "price" numeric not null, "total" numeric not null, "status" varchar not null default ('pending'), "patient_name" varchar, "patient_age" integer, "patient_gender" varchar, "health_concern" text, "prescription_path" varchar, "created_at" datetime, "updated_at" datetime, "doctor_id" integer, "base_price" numeric not null default '0', "gst_slab" numeric not null default '0', "gst_amount" numeric not null default '0', "cgst" numeric not null default '0', "sgst" numeric not null default '0', "igst" numeric not null default '0', "net_amount" numeric not null default '0', "hsn_code" varchar, foreign key("seller_id") references users("id") on delete set null on update no action, foreign key("product_id") references products("id") on delete cascade on update no action, foreign key("order_id") references orders("id") on delete cascade on update no action, foreign key("doctor_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "orders" ("id" integer primary key autoincrement not null, "order_number" varchar not null, "user_id" integer, "total_amount" numeric not null, "discount_amount" numeric not null default ('0'), "tax_amount" numeric not null default ('0'), "shipping_amount" numeric not null default ('0'), "final_amount" numeric not null, "status" varchar not null default ('pending'), "payment_status" varchar not null default ('pending'), "payment_method" varchar not null, "shipping_address_json" text not null, "billing_address_json" text not null, "coupon_code" varchar, "created_at" datetime, "updated_at" datetime, "order_notes" text, "igst" numeric not null default '0', "shipping_method_id" integer, "cgst" numeric not null default '0', "sgst" numeric not null default '0', "admin_commission" numeric not null default '0', "seller_earnings" numeric not null default '0', "platform_commission_percentage" numeric not null default '0', "payment_gateway_percentage" numeric not null default '0', "platform_commission_amount" numeric not null default '0', "payment_gateway_fee" numeric not null default '0', "commission_calculated_at" datetime, "tracking_id" varchar, "tracking_provider" varchar, "checkout_rating" integer, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("shipping_method_id") references "shipping_methods"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "payouts" ("id" integer primary key autoincrement not null, "user_id" integer not null, "amount" numeric not null, "status" varchar not null default ('pending'), "payment_method" varchar, "transaction_id" varchar, "notes" text, "created_at" datetime, "updated_at" datetime, "seller_id" integer, "requested_amount" numeric not null default '0', "approved_amount" numeric, "bank_details" text, "requested_at" datetime, "processed_at" datetime, "processed_by" integer, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("seller_id") references "users"("id") on delete cascade, foreign key("processed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime, "ip_address" varchar, "user_agent" text);
CREATE TABLE IF NOT EXISTS "prescriptions" ("id" integer primary key autoincrement not null, "prescription_number" varchar not null, "user_id" integer not null, "doctor_id" integer, "date" date not null, "patient_details" text not null, "vitals" text, "chief_complaints" text, "diagnosis" text, "medicines" text not null, "advice" text, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("doctor_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "product_attribute_values" ("id" integer primary key autoincrement not null, "product_id" integer not null, "attribute_value_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("product_id") references "products"("id") on delete cascade, foreign key("attribute_value_id") references "attribute_values"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "product_change_requests" ("id" integer primary key autoincrement not null, "product_id" integer not null, "seller_id" integer not null, "change_type" varchar check ("change_type" in ('create', 'edit', 'delete')) not null default 'edit', "proposed_data" text, "original_data" text, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "rejection_reason" text, "reviewed_by" integer, "reviewed_at" datetime, "created_at" datetime, "updated_at" datetime, "gst_slab" numeric default '18', "gst_inclusive" tinyint(1) default '1', foreign key("product_id") references "products"("id") on delete cascade, foreign key("seller_id") references "users"("id") on delete cascade, foreign key("reviewed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "product_tag" ("id" integer primary key autoincrement not null, "product_id" integer not null, "tag_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("product_id") references "products"("id") on delete cascade, foreign key("tag_id") references "tags"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "product_variants" ("id" integer primary key autoincrement not null, "product_id" integer not null, "sku" varchar, "attributes" text not null, "price" numeric not null, "original_price" numeric, "stock" integer not null default '0', "stock_status" varchar not null default 'in_stock', "image" varchar, "is_default" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "product_waitlists" ("id" integer primary key autoincrement not null, "product_id" integer not null, "user_id" integer, "email" varchar not null, "phone" varchar, "notified" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("product_id") references "products"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "products" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "sku" varchar, "brand_id" integer, "category_id" integer, "seller_id" integer, "price" numeric not null, "original_price" numeric, "stock_status" varchar not null default ('in_stock'), "stock" integer not null default ('0'), "image" varchar, "images" text, "video_url" varchar, "short_description" text, "long_description" text, "highlights" text, "specifications" text, "return_policy" text, "warranty_info" text, "variants" text, "tags" text, "seo_title" varchar, "seo_description" text, "meta_schema" text, "rating" numeric not null default ('0'), "reviews_count" integer not null default ('0'), "sales_count" integer not null default ('0'), "views_count" integer not null default ('0'), "status" varchar not null default ('draft'), "created_at" datetime, "updated_at" datetime, "concern_id" integer, "additional_info" text, "bought_last_month" integer not null default '0', "banners" text, "faqs" text, "is_prescription_required" tinyint(1) not null default '0', "deleted_at" datetime, "video_cover" varchar, "video_file" varchar, "gst_slab" numeric not null default '18', "gst_inclusive" tinyint(1) not null default '1', "hsn_code" varchar, "is_bestseller" tinyint(1) not null default '0', "is_new_arrival" tinyint(1) not null default '0', foreign key("seller_id") references users("id") on delete cascade on update no action, foreign key("category_id") references categories("id") on delete set null on update no action, foreign key("brand_id") references brands("id") on delete set null on update no action, foreign key("concern_id") references "categories"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "rating_aggregates" ("id" integer primary key autoincrement not null, "aggregatable_type" varchar not null, "aggregatable_id" integer not null, "average_rating" numeric not null default '0', "total_reviews" integer not null default '0', "rating_1_count" integer not null default '0', "rating_2_count" integer not null default '0', "rating_3_count" integer not null default '0', "rating_4_count" integer not null default '0', "rating_5_count" integer not null default '0', "last_calculated_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "recently_viewed_products" ("id" integer primary key autoincrement not null, "user_id" integer not null, "product_id" integer not null, "viewed_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "referrals" ("id" integer primary key autoincrement not null, "referrer_id" integer not null, "referred_user_id" integer, "referral_code" varchar not null, "status" varchar not null default 'pending', "reward_points" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("referrer_id") references "users"("id") on delete cascade, foreign key("referred_user_id") references "users"("id") on delete set null);
